// Parse the AI Agent's output — handles both JSON and plain text responses
let raw = $json.output ?? "";
if (typeof raw === 'object') raw = JSON.stringify(raw);
raw = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();

const FALLBACK_REPLY = "Sorry, I had a moment of trouble. Could you please repeat your question?";

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (err) {
  // Agent returned plain text — extract lead signals via pattern matching on the reply
  const agentReply = raw;

  const emailMatch = agentReply.match(/[\w.+-]+@[\w.-]+\.[a-z]{2,}/i);
  const phoneMatch = agentReply.match(/(?:\+?\d{1,3}[\s-]?)?\d{7,}/);
  const nameMatch  = agentReply.match(/(?:thank(?:s| you)[,!]?\s+|hi[,!]?\s+|hello[,!]?\s+|dear\s+)([A-Za-z]+(?:\s+[A-Za-z]+)?)/i);

  let score = 0;
  if (/sales.*(?:contact|reach|call)|reach out|follow.?up|get back to you/i.test(agentReply)) score += 40;
  if (phoneMatch)  score += 20;
  if (emailMatch)  score += 10;
  if (/tomorrow|today|after\s*\d|by\s*\d|asap/i.test(agentReply))                            score += 15;
  if (/zip blind|motoris|motor|model|series|instal|pric|quot/i.test(agentReply))              score += 15;
  if (/commercial|bulk|multiple|project|\d+\s*unit/i.test(agentReply))                       score += 20;

  return [{
    json: {
      parse_success: false,
      Name:          nameMatch ? nameMatch[1].trim() : "",
      Email:         emailMatch ? emailMatch[0] : "",
      reply_to_user: (agentReply && agentReply.length < 4000) ? agentReply : FALLBACK_REPLY,
      lead_score:    Math.min(score, 100),
      qualified:     score >= 70,
      product_interest: "",
      conversation_summary: "",
      error: "Plain text from agent — signals extracted"
    }
  }];
}

const name  = parsed.lead_data?.name  || "";
const email = parsed.lead_data?.email || "";
const reply = parsed.reply_to_user    || FALLBACK_REPLY;
const score = typeof parsed.lead_score === 'number' ? parsed.lead_score : 0;

return [{
  json: {
    parse_success: true,
    Name:          name,
    Email:         email,
    reply_to_user: reply,
    lead_score:    score,
    qualified:     parsed.qualified || false,
    product_interest: parsed.lead_data?.product_interest || "",
    conversation_summary: parsed.conversation_summary || ""
  }
}];

